/// 增强的 TS 文件验证函数
pub fn is_valid_ts_file_enhanced(path: &Path) -> bool {
    match File::open(path) {
        Ok(mut file) => {
            let mut buffer = [0u8; 188]; // 读取一个 TS 包的大小
            if file.read_exact(&mut buffer).is_ok() {
                // 方法1：检查前 4 个字节是否为 0x47
                if buffer[0] == 0x47 {
                    return true;
                }

                // 方法2：在文件中搜索 0x47 同步字节
