    }
}

pub enum ValidationResult {
    Valid,
    ValidWithWarning(String),
    Invalid(String),
}

fn search_sync_byte(path: &Path) -> bool {
    match File::open(path) {
        Ok(mut file) => {
            let mut buffer = [0u8; 4096]; // 读取 4KB
            if file.read_exact(&mut buffer).is_ok() {
                // 搜索 0x47 同步字节
                buffer.iter().any(|&b| b == 0x47)
            } else {
                false
            }
        }
        Err(_) => false,
    }
}
