/// 检查TS文件是否有效（通过检查文件头）
pub fn is_valid_ts_file(path: &Path) -> bool {
    File::open(path).is_ok_and(|mut file| {
        let mut buffer = [0u8; 4];
        if file.read_exact(&mut buffer).is_ok() {
            // TS文件通常以0x47开头（MPEG-TS同步字节）
            buffer[0] == TS_SYNC_BYTE
        } else {
            false
        }
    })
}

/// 解析URL
pub fn resolve_url(base_url: &url::Url, url: &str) -> Result<String> {
    if url.starts_with("http://") || url.starts_with("https://") {
        Ok(url.to_string())
    } else {
        base_url
            .join(url)
            .map(|u| u.to_string())
            .map_err(|e| DownloadError::parse(format!("URL解析失败: {e}")))
    }
}

