/// 从JSON文件加载下载任务
pub fn load_download_tasks_from_json(json_path: &str) -> Result<Vec<DownloadTask>> {
    // 读取JSON文件
    let json_content = fs::read_to_string(json_path)
        .map_err(|e| DownloadError::file(json_path, format!("读取JSON文件失败: {e}")))?;

