                            .await;
                    }

                    log::info!("✅ 任务 {task_id} 下载完成");
                }
                Err(e) => {
                    let _ = state
                        .update_task_status(&task_id, TaskStatus::Failed, Some(e.to_string()))
                        .await;
                    log::error!("❌ 任务 {task_id} 下载失败: {e}");
                }
            }
        }
        Err(e) => {
            let _ = state
                .update_task_status(&task_id, TaskStatus::Failed, Some(e.to_string()))
