    let mut stdout = child
        .stdout
        .take()
        .ok_or_else(|| DownloadError::ffmpeg("无法获取FFmpeg标准输出".to_string()))?;
    let mut stderr = child
        .stderr

])
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|e| DownloadError::ffmpeg(format!("启动FFmpeg失败: {e}")))?;

    let mut stdout = child
        .stdout
        .take()
        .ok_or_else(|| DownloadError::ffmpeg("无法获取FFmpeg标准输出".to_string()))?;
    let mut stderr = child
        .stderr
        .take()
        .ok_or_else(|| DownloadError::ffmpeg("无法获取FFmpeg标准错误输出".to_string()))?;
    let mut buf = vec![0u8; 65536];
    let stderr_task = tokio::spawn(async move {
        let mut stderr_buf = Vec::new();
        let _ = stderr.read_to_end(&mut stderr_buf).await;
        stderr_buf
    });

    loop {
        let n = stdout
            .read(&mut buf)
            .await
            .map_err(|e| DownloadError::ffmpeg(format!("读取FFmpeg输出失败: {e}")))?;
        if n == 0 {
            break;
        }
        let _ = tx.send(Ok(bytes::Bytes::copy_from_slice(&buf[..n]))).await;
    }

    let status = child
        .wait()
        .await
        .map_err(|e| DownloadError::ffmpeg(format!("等待FFmpeg失败: {e}")))?;
    let stderr_output = stderr_task.await.unwrap_or_default();

    if !status.success() {
        let stderr_text = String::from_utf8_lossy(&stderr_output).trim().to_string();
        if stderr_text.is_empty() {
            return Err(DownloadError::ffmpeg("FFmpeg转换失败".to_string()));
        }
        return Err(DownloadError::ffmpeg(format!("FFmpeg转换失败: {stderr_text}")));
    }

    Ok(())
}

const tabLinks = new Map();
const BACKEND_URL = "http://localhost:8080";

function normalizeUrl(url) {
  try {
    return new URL(url).href;
  } catch (_) {
    return "";
  }
}

function isM3u8Url(url) {
  return /\.m3u8(?:[?#]|$)/i.test(url);
}

function rememberLink(tabId, url) {
  if (tabId < 0 || !url) return;

  const normalized = normalizeUrl(url);
  if (!normalized || !isM3u8Url(normalized)) return;

  const links = tabLinks.get(tabId) || [];
  if (links.includes(normalized)) return;

  links.push(normalized);
  tabLinks.set(tabId, links);

  chrome.tabs
    .sendMessage(tabId, { type: "M3U8_LINKS_UPDATED", links })
    .catch(() => {
      // The content script may not be available on browser pages or restricted sites.
    });
}

function sanitizeFileName(name) {
  return (name || "m3u8_video")
    .replace(/[\\/:*?"<>|]/g, "_")
    .replace(/\s+/g, "_")
    .slice(0, 80);
}

function taskNameFromUrl(url) {
  try {
    const parsed = new URL(url);
    const last = parsed.pathname.split("/").filter(Boolean).pop() || "m3u8_video";
    return sanitizeFileName(decodeURIComponent(last).replace(/\.m3u8$/i, ""));
  } catch (_) {
    return `m3u8_video_${Date.now()}`;
  }
}

